class Solution:
    def stoneGameIX(self, stones: List[int]) -> bool:
        def check(cnt: List[int]) -> bool:
            if cnt[1] == 0:
                return False
            cnt[1] -= 1
            r = 1 + min(cnt[1], cnt[2]) * 2 + cnt[0]
            if cnt[1] > cnt[2]:
                cnt[1] -= 1
                r += 1
            return r % 2 == 1 and cnt[1] != cnt[2]

        c1 = [0] * 3
        for x in stones:
            c1[x % 3] += 1
        c2 = [c1[0], c1[2], c1[1]]
        return check(c1) or check(c2)

class Solution:
    def maxConsecutiveAnswers(self, answerKey: str, k: int) -> int:
        def f(c: str) -> int:
            cnt = l = 0
            for ch in answerKey:
                cnt += ch == c
                if cnt > k:
                    cnt -= answerKey[l] == c
                    l += 1
            return len(answerKey) - l

        return max(f("T"), f("F"))

class Solution:
    def smallestSubsequence(self, s: str, k: int, letter: str, repetition: int) -> str:
        # Counting total occurrences of 'letter'
        total_letter = s.count(letter)
        used_letter = 0
        stack = []
        n = len(s)

        for i, char in enumerate(s):
            # Monotonic stack logic with constraints:
            # 1. Total remaining characters must be enough to reach length k
            # 2. Total remaining 'letter' must be enough to reach 'repetition'
            while stack and stack[-1] > char and (len(stack) + (n - i) > k):
                # If the character we're popping is 'letter', check if we have enough left
                if stack[-1] == letter:
                    if (used_letter - 1) + (total_letter) < repetition:
                        break
                    used_letter -= 1
                stack.pop()

            # Deciding whether to push the current character
            if len(stack) < k:
                if char == letter:
                    stack.append(char)
                    used_letter += 1
                else:
                    # Only push non-'letter' if we have space to still include required 'letter's later
                    if k - len(stack) > max(0, repetition - used_letter):
                        stack.append(char)

            if char == letter:
                total_letter -= 1

        return "".join(stack)

import heapq

class StockPrice:
    def __init__(self):
        self.time_price = {}
        self.latest_time = 0
        self.min_heap = [] # (price, timestamp)
        self.max_heap = [] # (-price, timestamp)

    def update(self, timestamp: int, price: int) -> None:
        self.time_price[timestamp] = price
        self.latest_time = max(self.latest_time, timestamp)
        heapq.heappush(self.min_heap, (price, timestamp))
        heapq.heappush(self.max_heap, (-price, timestamp))

    def current(self) -> int:
        return self.time_price[self.latest_time]

    def maximum(self) -> int:
        # Lazy deletion from heap
        while True:
            price, timestamp = self.max_heap[0]
            if -price == self.time_price[timestamp]:
                return -price
            heapq.heappop(self.max_heap)

    def minimum(self) -> int:
        # Lazy deletion from heap
        while True:
            price, timestamp = self.min_heap[0]
            if price == self.time_price[timestamp]:
                return price
            heapq.heappop(self.min_heap)

class Solution:
    def minOperations(self, grid: List[List[int]], x: int) -> int:
        nums = []
        mod = grid[0][0] % x
        for row in grid:
            for v in row:
                if v % x != mod:
                    return -1
                nums.append(v)
        nums.sort()
        mid = nums[len(nums) >> 1]
        return sum(abs(v - mid) // x for v in nums)

class Solution:
    def minimumDifference(self, nums: List[int]) -> int:
        n = len(nums) >> 1
        f = defaultdict(set)
        g = defaultdict(set)
        for i in range(1 << n):
            s = cnt = 0
            s1 = cnt1 = 0
            for j in range(n):
                if (i & (1 << j)) != 0:
                    s += nums[j]
                    cnt += 1
                    s1 += nums[n + j]
                    cnt1 += 1
                else:
                    s -= nums[j]
                    s1 -= nums[n + j]
            f[cnt].add(s)
            g[cnt1].add(s1)

        ans = inf
        for i in range(n + 1):
            fi, gi = sorted(list(f[i])), sorted(list(g[n - i]))
            # min(abs(f[i] + g[n - i]))
            for a in fi:
                left, right = 0, len(gi) - 1
                b = -a
                while left < right:
                    mid = (left + right) >> 1
                    if gi[mid] >= b:
                        right = mid
                    else:
                        left = mid + 1
                ans = min(ans, abs(a + gi[left]))
                if left > 0:
                    ans = min(ans, abs(a + gi[left - 1]))
        return ans

class Solution:
