class Solution:
    def possiblyEquals(self, s1: str, s2: str) -> bool:
        # Memoization: (i, j, balance)
        # balance = length(s1_prefix) - length(s2_prefix)
        memo = {}

        def get_diffs(s, i):
            # Get all possible jump lengths from digits starting at i
            diffs = {0}
            j = i
            while j < len(s) and s[j].isdigit():
                val = int(s[i:j+1])
                diffs.add(val)
                j += 1
            return diffs, j

        @functools.lru_cache(None)
        def solve(i, j, diff):
            if i == len(s1) and j == len(s2):
                return diff == 0

            # s1 has digits
            if i < len(s1) and s1[i].isdigit():
                k = i
                val = 0
                while k < len(s1) and s1[k].isdigit():
                    val = val * 10 + int(s1[k])
                    k += 1
                    if solve(k, j, diff + val): return True
                return False

            # s2 has digits
            if j < len(s2) and s2[j].isdigit():
                k = j
                val = 0
                while k < len(s2) and s2[k].isdigit():
                    val = val * 10 + int(s2[k])
                    k += 1
                    if solve(i, k, diff - val): return True
                return False

            # Both are characters or one is exhausted
            if diff > 0:
                # s1 is longer, consume s2 char
                if j < len(s2): return solve(i, j + 1, diff - 1)
            elif diff < 0:
                # s2 is longer, consume s1 char
                if i < len(s1): return solve(i + 1, j, diff + 1)
            else:
                # diff == 0, both must match
                if i < len(s1) and j < len(s2) and s1[i] == s2[j]:
                    return solve(i + 1, j + 1, 0)

            return False

        return solve(0, 0, 0)

class Solution:
    def minimumOperations(self, nums: List[int], start: int, goal: int) -> int:
        op1 = lambda x, y: x + y
        op2 = lambda x, y: x - y
        op3 = lambda x, y: x ^ y
        ops = [op1, op2, op3]
        vis = [False] * 1001
        q = deque([(start, 0)])
        while q:
            x, step = q.popleft()
            for num in nums:
                for op in ops:
                    nx = op(x, num)
                    if nx == goal:
                        return step + 1
                    if 0 <= nx <= 1000 and not vis[nx]:
                        q.append((nx, step + 1))
                        vis[nx] = True
        return -1

