class Solution:
    def sumScores(self, s: str) -> int:
        # Z-Algorithm calculates the longest common prefix between s and s[i:]
        n = len(s)
        z = [0] * n
        l, r = 0, 0
        for i in range(1, n):
            if i <= r:
                z[i] = min(r - i + 1, z[i - l])
            while i + z[i] < n and s[z[i]] == s[i + z[i]]:
                z[i] += 1
            if i + z[i] - 1 > r:
                l, r = i, i + z[i] - 1

        # Total score is sum of Z-values plus the length of s itself (for s_n)
        return sum(z) + n

