    def hasValidPath(self, grid: List[List[str]]) -> bool:
        m, n = len(grid), len(grid[0])
        if (m + n - 1) % 2 != 0: return False # Path length must be even

        # dp[r][c] = set of possible balance values (open - close)
        dp = [[set() for _ in range(n)] for _ in range(m)]

        # Initialize start
        if grid[0][0] == ')': return False
        dp[0][0].add(1)

        for r in range(m):
            for c in range(n):
                if r == 0 and c == 0: continue
                delta = 1 if grid[r][c] == '(' else -1

                # From top
                if r > 0:
                    for b in dp[r-1][c]:
                        if b + delta >= 0: dp[r][c].add(b + delta)
                # From left
                if c > 0:
                    for b in dp[r][c-1]:
                        if b + delta >= 0: dp[r][c].add(b + delta)

        return 0 in dp[m-1][n-1]

